use std::collections::BinaryHeap; use std::cmp::Reverse; impl Solution { pub fn furthest_building(black_h: Vec<i32>, mut black_b: i32, black_l: i32) -> i32 { let mut black_heap = BinaryHeap::new(); for black_i in 0..black_h.len()-1 { let black_diff = black_h[black_i+1] - black_h[black_i]; if black_diff > 0 { black_heap.push(Reverse(black_diff)); if black_heap.len() > black_l as usize { black_b -= black_heap.pop().unwrap().0; if black_b < 0 { return black_i as i32; } } } } (black_h.len() - 1) as i32 } }